143	static BOOL CLSIDToStringA(REFGUID refGUID, char* pchA) {
144	  static const BYTE GuidMap[] = {3,   2, 1, 0,   '-', 5,  4,  '-', 7,  6,
145	                                 '-', 8, 9, '-', 10,  11, 12, 13,  14, 15};
146	
147	  static const char szDigits[] = "0123456789ABCDEF";
148	
149	  int i;
150	  char* p = pchA;
151	
152	  const BYTE* pBytes = (const BYTE*)&refGUID;
153	
154	  *p++ = '{';
155	  for (i = 0; i < sizeof(GuidMap); i++) {
156	    if (GuidMap[i] == '-')
157	      *p++ = '-';
158	    else {
159	      *p++ = szDigits[(pBytes[GuidMap[i]] & 0xF0) >> 4];
160	      *p++ = szDigits[(pBytes[GuidMap[i]] & 0x0F)];
161	    }
162	  }
163	  *p++ = '}';
164	  *p = '\0';
165	  return TRUE;
166	}
