168	static LONG RecurseDeleteKeyA(HKEY hParentKey, LPCSTR lpszKey) {
169	  HKEY hKey;
170	  LONG lRes;
171	  FILETIME time;
172	  CHAR szBuffer[256];
173	  DWORD dwSize = ARRAYSIZE(szBuffer);
174	
175	  if (RegOpenKeyA(hParentKey, lpszKey, &hKey) != ERROR_SUCCESS)
176	    return ERROR_SUCCESS;
177	
178	  lRes = ERROR_SUCCESS;
179	  while (RegEnumKeyExA(hKey, 0, szBuffer, &dwSize, NULL, NULL, NULL, &time) ==
180	         ERROR_SUCCESS) {
181	    szBuffer[ARRAYSIZE(szBuffer) - 1] = '\0';
182	    lRes = RecurseDeleteKeyA(hKey, szBuffer);
183	    if (lRes != ERROR_SUCCESS)
184	      break;
185	    dwSize = ARRAYSIZE(szBuffer);
186	  }
187	  RegCloseKey(hKey);
188	
189	  return lRes == ERROR_SUCCESS ? RegDeleteKeyA(hParentKey, lpszKey) : lRes;
190	}
