192	BOOL RegisterServer() {
193	  DWORD dw;
194	  HKEY hKey;
195	  HKEY hSubKey;
196	  BOOL fRet;
197	  char achIMEKey[ARRAYSIZE(c_szInfoKeyPrefix) + CLSID_STRLEN];
198	  char achFileName[MAX_PATH];
199	
200	  if (!CLSIDToStringA(c_clsidTextService,
201	                      achIMEKey + ARRAYSIZE(c_szInfoKeyPrefix) - 1))
202	    return FALSE;
203	  memcpy(achIMEKey, c_szInfoKeyPrefix, sizeof(c_szInfoKeyPrefix) - 1);
204	
205	  if (fRet = RegCreateKeyExA(HKEY_CLASSES_ROOT, achIMEKey, 0, NULL,
206	                             REG_OPTION_NON_VOLATILE, KEY_WRITE, NULL, &hKey,
207	                             &dw) == ERROR_SUCCESS) {
208	    fRet &= RegSetValueExA(hKey, NULL, 0, REG_SZ, (BYTE*)TEXTSERVICE_DESC_A,
209	                           sizeof TEXTSERVICE_DESC_A) == ERROR_SUCCESS;
210	    if (fRet &=
211	        RegCreateKeyExA(hKey, c_szInProcSvr32, 0, NULL, REG_OPTION_NON_VOLATILE,
212	                        KEY_WRITE, NULL, &hSubKey, &dw) == ERROR_SUCCESS) {
213	      dw = GetModuleFileNameA(g_hInst, achFileName, ARRAYSIZE(achFileName));
214	
215	#ifdef _M_ARM64
216	      {
217	        // On ARM64 we use ARM64X redirection DLL.
218	        // When loaded, weasel.dll will be redirected to weaselARM64.dll on
219	        // ARM64 processes, and weaselx64.dll on x64 processes.
220	        //
221	        // But GetModuleFileNameA will return the actual loaded DLL name aka
222	        // weaselARM64.dll Rewrite the path to point to the redirector.
223	
224	        char wrapperPath[MAX_PATH];
225	        StringCbCatA(achFileName, MAX_PATH, "\\..\\weasel.dll");
226	        GetFullPathNameA(achFileName, MAX_PATH, wrapperPath, NULL);
227	        memcpy(achFileName, wrapperPath, MAX_PATH);
228	      }
229	#endif
230	
231	      fRet &= RegSetValueExA(hSubKey, NULL, 0, REG_SZ, (BYTE*)achFileName,
232	                             (strlen(achFileName) + 1) * sizeof(char)) ==
233	              ERROR_SUCCESS;
234	      fRet &= RegSetValueExA(hSubKey, c_szModelName, 0, REG_SZ,
235	                             (BYTE*)TEXTSERVICE_MODEL,
236	                             sizeof TEXTSERVICE_MODEL) == ERROR_SUCCESS;
237	      RegCloseKey(hSubKey);
238	    }
239	    RegCloseKey(hKey);
240	  }
241	  return fRet;
242	}
