248	    return;
249	  memcpy(achIMEKey, c_szInfoKeyPrefix, sizeof(c_szInfoKeyPrefix) - 1);
250	  RecurseDeleteKeyA(HKEY_CLASSES_ROOT, achIMEKey);
251	
252	  // On Windows 8, we need to manually delete the registry key for our TIP
253	  char tipKey[ARRAYSIZE(c_szTipKeyPrefix) + CLSID_STRLEN];
254	  if (!CLSIDToStringA(c_clsidTextService,
255	                      tipKey + ARRAYSIZE(c_szTipKeyPrefix) - 1))
256	    return;
257	  memcpy(tipKey, c_szTipKeyPrefix, sizeof(c_szTipKeyPrefix) - 1);
258	  RecurseDeleteKeyA(HKEY_CLASSES_ROOT, tipKey);
259	}
