242	    if (retry >= 6) {
243	      HANDLE hMutex = CreateMutex(NULL, TRUE, L"WeaselDeployerExclusiveMutex");
244	      const auto count_server_process = []() -> int {
245	        int count = 0;
246	        HANDLE snap = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
247	        if (snap == INVALID_HANDLE_VALUE)
248	          return 0;
249	        PROCESSENTRY32 pe;
250	        pe.dwSize = sizeof(pe);
251	        if (Process32First(snap, &pe)) {
252	          do {
253	            if (_wcsicmp(pe.szExeFile, L"WeaselServer.exe") == 0)
254	              count++;
255	          } while (Process32Next(snap, &pe));
256	        }
257	        CloseHandle(snap);
258	        return count;
259	      };
260	      if (!m_client.Echo() && GetLastError() != ERROR_ALREADY_EXISTS &&
261	          !count_server_process()) {
262	        std::wstring dir = _GetRootDir();
263	        std::thread th([dir, this]() {
264	          ShellExecuteW(NULL, L"open", (dir + L"\\start_service.bat").c_str(),
265	                        NULL, dir.c_str(), SW_HIDE);
266	          // wait 500ms, then reconnect
267	          std::this_thread::sleep_for(std::chrono::milliseconds(500));
268	          _Reconnect();
269	        });
270	        th.detach();
271	      }
272	      if (hMutex) {
273	        CloseHandle(hMutex);
274	      }
275	      retry = 0;
276	    }
277	    return (m_client.Echo() != 0);
278	  } else {
279	    return true;
280	  }
